example.code:
// i18n/messages.ts
export const messages = {
  en: {
    'app.welcome': 'Welcome, {name}!',
    'app.items': '{count, plural, =0 {No items} one {# item} other {# items}}',
    'order.total': 'Total: {amount, number, currency}',
  },
  uk: {
    'app.welcome': 'Ласкаво просимо, {name}!',
    'app.items': '{count, plural, one {# елемент} few {# елементи} many {# елементів} other {# елемента}}',
    'order.total': 'Всього: {amount, number, currency}',
  },
};

// App.tsx
function App() {
  const [locale, setLocale] = useState('en');
  return (
    <IntlProvider locale={locale} messages={messages[locale]}>
      <Routes />
    </IntlProvider>
  );
}

// Component
function CartSummary({ itemCount, total }: Props) {
  return (
    <div>
      <FormattedMessage id="app.items" values={{ count: itemCount }} />
      <FormattedMessage id="order.total" values={{ amount: total }} />
    </div>
  );
}

.card {
  margin-inline-start: 1rem;   /* left in LTR, right in RTL */
  margin-inline-end: 1rem;
  padding-inline: 1.5rem;
  text-align: start;           /* not left */
  border-inline-start: 2px solid blue;
}

[dir="rtl"] .icon-arrow {
  transform: scaleX(-1);       /* flip directional icons */
}

function App() {
  const intl = useIntl();
  const isRTL = ['ar', 'he', 'fa'].includes(intl.locale);
  return <div dir={isRTL ? 'rtl' : 'ltr'}><Content /></div>;
}
